// ═══ 📦 INPUT & DATE PARSER v2.0 ═══
// Soporta: "ayer", "el lunes", "15 de febrero", "semana pasada", etc.

let query = 'genera el reporte semanal automático';
let chatId = '6908159885';
let source = 'schedule';

try {
  const trigger = $('When Executed by Another Workflow').first().json;
  if (trigger && (trigger.query || trigger.message)) {
    query = trigger.query || trigger.message?.text || trigger.message || query;
    chatId = trigger.chatId || trigger.message?.chat?.id || chatId;
    source = 'manual';
  }
} catch(e) {}

const now = new Date(new Date().toLocaleString('en-US', {timeZone: 'America/Bogota'}));
const monthNames = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
const dayNames = ['domingo','lunes','martes','miércoles','jueves','viernes','sábado'];

// ═══ PARSER DE FECHAS EN LENGUAJE NATURAL ═══
const q = query.toLowerCase();
let targetDate = new Date(now);
let periodType = 'today';
let customStart = null;
let customEnd = null;

// "ayer" / "yesterday"
if (q.includes('ayer') || q.includes('yesterday')) {
  targetDate.setDate(now.getDate() - 1);
  periodType = 'specific_day';
}
// "anteayer" / "hace 2 días"
else if (q.includes('anteayer') || q.includes('hace 2 día')) {
  targetDate.setDate(now.getDate() - 2);
  periodType = 'specific_day';
}
// "el lunes", "el martes", etc.
else if (q.match(/\b(el |del )?(lunes|martes|miércoles|miercoles|jueves|viernes|sábado|sabado|domingo)\b/)) {
  const dayMatch = q.match(/(lunes|martes|miércoles|miercoles|jueves|viernes|sábado|sabado|domingo)/);
  if (dayMatch) {
    const targetDayName = dayMatch[1].replace('miercoles','miércoles').replace('sabado','sábado');
    const targetDayIndex = dayNames.indexOf(targetDayName);
    const currentDay = now.getDay();
    let diff = currentDay - targetDayIndex;
    if (diff <= 0) diff += 7; // Si es hoy o futuro, ir a la semana pasada
    targetDate.setDate(now.getDate() - diff);
    periodType = 'specific_day';
  }
}
// "hace X días"
else if (q.match(/hace (\d+) día/)) {
  const m = q.match(/hace (\d+) día/);
  targetDate.setDate(now.getDate() - parseInt(m[1]));
  periodType = 'specific_day';
}
// "15 de febrero", "febrero 15", "15/02"
else if (q.match(/(\d{1,2})\s*(de\s+)?(enero|febrero|marzo|abril|mayo|junio|julio|agosto|septiembre|octubre|noviembre|diciembre)/i)) {
  const m = q.match(/(\d{1,2})\s*(de\s+)?(enero|febrero|marzo|abril|mayo|junio|julio|agosto|septiembre|octubre|noviembre|diciembre)/i);
  const day = parseInt(m[1]);
  const monthName = m[3].toLowerCase();
  const monthIndex = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'].indexOf(monthName);
  targetDate = new Date(now.getFullYear(), monthIndex, day);
  if (targetDate > now) targetDate.setFullYear(now.getFullYear() - 1); // Si es futuro, año pasado
  periodType = 'specific_day';
}
// "semana pasada" / "la semana anterior"
else if (q.includes('semana pasada') || q.includes('semana anterior')) {
  const dayOfWeek = now.getDay() || 7;
  const lastMonday = new Date(now);
  lastMonday.setDate(now.getDate() - dayOfWeek - 6);
  const lastSunday = new Date(lastMonday);
  lastSunday.setDate(lastMonday.getDate() + 6);
  customStart = lastMonday.toISOString().split('T')[0];
  customEnd = lastSunday.toISOString().split('T')[0];
  periodType = 'week';
}
// "mes pasado" / "mes anterior" / "febrero" (mes específico)
else if (q.includes('mes pasado') || q.includes('mes anterior')) {
  const lastMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
  const lastMonthEnd = new Date(now.getFullYear(), now.getMonth(), 0);
  customStart = lastMonth.toISOString().split('T')[0];
  customEnd = lastMonthEnd.toISOString().split('T')[0];
  targetDate = lastMonth;
  periodType = 'month';
}
// "de febrero" / "en marzo" (mes específico)
else if (q.match(/\b(de |en )?(enero|febrero|marzo|abril|mayo|junio|julio|agosto|septiembre|octubre|noviembre|diciembre)\b/i) && !q.match(/\d{1,2}/)) {
  const m = q.match(/(enero|febrero|marzo|abril|mayo|junio|julio|agosto|septiembre|octubre|noviembre|diciembre)/i);
  const monthName = m[1].toLowerCase();
  const monthIndex = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'].indexOf(monthName);
  let year = now.getFullYear();
  if (monthIndex > now.getMonth()) year--; // Si es mes futuro, año pasado
  targetDate = new Date(year, monthIndex, 1);
  customStart = new Date(year, monthIndex, 1).toISOString().split('T')[0];
  customEnd = new Date(year, monthIndex + 1, 0).toISOString().split('T')[0];
  periodType = 'month';
}
// "esta semana" / "semanal"
else if (q.includes('esta semana') || q.includes('semanal') || q.includes('de la semana')) {
  periodType = 'week';
}
// "este mes" / "mensual"
else if (q.includes('este mes') || q.includes('mensual') || q.includes('del mes')) {
  periodType = 'month';
}
// "hoy"
else if (q.includes('hoy') || q.includes('de hoy')) {
  periodType = 'specific_day';
}

// ═══ CALCULAR RANGOS ═══
const targetMonth = targetDate.getMonth();
const targetYear = targetDate.getFullYear();
const monthSheet = monthNames[targetMonth];

// Rango del mes target
const firstDayOfMonth = new Date(targetYear, targetMonth, 1).toISOString().split('T')[0];
const lastDayOfMonth = new Date(targetYear, targetMonth + 1, 0).toISOString().split('T')[0];

// Rango de la semana actual
const dayOfWeek = now.getDay() || 7;
const monday = new Date(now);
monday.setDate(now.getDate() - dayOfWeek + 1);

// Para días específicos
const specificDay = targetDate.toISOString().split('T')[0];

// Period label
let periodLabel = '';
if (periodType === 'specific_day') {
  periodLabel = `${targetDate.getDate()} de ${monthNames[targetMonth]} ${targetYear}`;
} else if (periodType === 'week') {
  periodLabel = `Semana del ${customStart || monday.toISOString().split('T')[0]}`;
} else {
  periodLabel = `${monthSheet} ${targetYear}`;
}

return [{ json: {
  query, chatId, source,
  periodType,
  targetDate: targetDate.toISOString(),
  specificDay,
  monthSheet,
  monthName: monthSheet,
  year: targetYear,
  day: targetDate.getDate(),
  periodMonth: `${monthSheet} ${targetYear}`,
  periodLabel,
  firstDayOfMonth,
  lastDayOfMonth,
  weekStart: customStart || monday.toISOString().split('T')[0],
  weekEnd: customEnd || now.toISOString().split('T')[0],
  customStart,
  customEnd,
  todayStr: now.toISOString().split('T')[0],
  reportTimestamp: now.toISOString(),
  _parsed: { periodType, targetDate: targetDate.toISOString(), query }
}}];

const aiRaw = $input.first().json;
const ctx = $('📦 Input & Date Parser').first().json;

let ai = {};
try {
  let text = aiRaw.output || aiRaw.text || '';
  if (typeof text !== 'string') text = JSON.stringify(text);
  text = text.replace(/```json\s*/gi,'').replace(/```\s*/gi,'').trim();
  const m = text.match(/\{[\s\S]*\}/);
  if (m) ai = JSON.parse(m[0]);
} catch(e) {
  ai = { report_type: ctx.periodType === 'specific_day' ? 'diario' : ctx.periodType === 'week' ? 'semanal' : 'mensual' };
}

// Determinar tipo basado en periodType parseado
let reportType = ai.report_type || 'semanal';
if (ctx.source === 'schedule') reportType = 'semanal';
else if (ctx.periodType === 'specific_day') reportType = 'diario';
else if (ctx.periodType === 'week') reportType = 'semanal';
else if (ctx.periodType === 'month') reportType = 'mensual';

return [{ json: { ...ctx, ...ai, report_type: reportType } }];

// ═══════════════════════════════════════════════════════════════
// ANALYSIS ENGINE v3.0 — EXTRACCION COMPLETA
// ═══════════════════════════════════════════════════════════════

const config = $('🔗 Config Bridge').first().json;

let habitsRaw = [], leadsRaw = [], emailLogRaw = [], controlRaw = [];
try { habitsRaw = $('📊 Read Habits').all().map(i => i.json); } catch(e) {}
try { leadsRaw = $('📊 Read Leads').all().map(i => i.json); } catch(e) {}
try { emailLogRaw = $('📊 Read Email Log').all().map(i => i.json); } catch(e) {}
try { controlRaw = $('📊 Read Outreach Control').all().map(i => i.json); } catch(e) {}

const now = new Date(new Date().toLocaleString('en-US', {timeZone: 'America/Bogota'}));
const meses = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
const diasSemana = ['Domingo','Lunes','Martes','Miercoles','Jueves','Viernes','Sabado'];
const reportType = config.report_type || 'semanal';

// ═══ PERIODO ═══
let periodStart, periodEnd, daysToAnalyze;

if (reportType === 'diario' && config.specificDay) {
  periodStart = new Date(config.specificDay + 'T00:00:00');
  periodEnd = new Date(config.specificDay + 'T23:59:59');
  daysToAnalyze = [periodStart.getDate()];
} else if (reportType === 'semanal') {
  periodStart = new Date((config.weekStart || config.customStart) + 'T00:00:00');
  periodEnd = new Date((config.weekEnd || config.customEnd) + 'T23:59:59');
  daysToAnalyze = [];
  const temp = new Date(periodStart);
  while (temp <= periodEnd) {
    daysToAnalyze.push(temp.getDate());
    temp.setDate(temp.getDate() + 1);
  }
} else {
  periodStart = new Date(config.firstDayOfMonth + 'T00:00:00');
  periodEnd = new Date(config.lastDayOfMonth + 'T23:59:59');
  const maxDay = Math.min(now.getDate(), new Date(config.lastDayOfMonth).getDate());
  daysToAnalyze = Array.from({length: maxDay}, (_, i) => i + 1);
}

const daysElapsed = daysToAnalyze.length;
const targetMonth = new Date(config.targetDate || now).getMonth();
const targetYear = new Date(config.targetDate || now).getFullYear();

// Periodo legible
let periodoCompleto = config.periodLabel || '';
if (reportType === 'semanal' && config.weekStart) {
  const ws = new Date(config.weekStart + 'T12:00:00');
  const we = new Date((config.weekEnd || config.customEnd || config.weekStart) + 'T12:00:00');
  const ms = meses[ws.getMonth()];
  const me = meses[we.getMonth()];
  periodoCompleto = ms === me
    ? `${ws.getDate()} - ${we.getDate()} de ${ms} de ${ws.getFullYear()}`
    : `${ws.getDate()} de ${ms} - ${we.getDate()} de ${me} de ${we.getFullYear()}`;
} else if (reportType === 'mensual') {
  periodoCompleto = `${meses[targetMonth]} ${targetYear}`;
} else if (reportType === 'diario' && config.specificDay) {
  const sd = new Date(config.specificDay + 'T12:00:00');
  periodoCompleto = `${diasSemana[sd.getDay()]}, ${sd.getDate()} de ${meses[sd.getMonth()]} de ${sd.getFullYear()}`;
}

// ═══════════════════════════════════════════════════════════════
// HABITOS — EXTRACCION PROFUNDA
// ═══════════════════════════════════════════════════════════════
const dailyCompletion = {};
let totalHabitSlots = 0, totalHabitDone = 0;
const habitStats = {};
const habitsByDay = {}; // dia -> [{name, done}]

for (const row of habitsRaw) {
  if (!row) continue;
  const keys = Object.keys(row);
  const nameKey = keys.find(k => ['B','col_2','HÁBITO','Habito','Habit'].includes(k));
  const habitName = nameKey ? String(row[nameKey] || '').trim() : '';
  if (!habitName || habitName.length < 2) continue;

  if (!habitStats[habitName]) habitStats[habitName] = {done: 0, total: 0, dailyDetail: []};

  for (const d of daysToAnalyze) {
    const dayKey = keys.find(k => k.trim() === String(d));
    if (!dayKey) continue;
    const val = String(row[dayKey] || '').toUpperCase().trim();
    const isDone = ['TRUE','1','SI','VERDADERO','✓','X','YES'].includes(val);

    habitStats[habitName].total++;
    if (isDone) habitStats[habitName].done++;
    habitStats[habitName].dailyDetail.push({day: d, done: isDone});

    if (!dailyCompletion[d]) dailyCompletion[d] = {done: 0, total: 0};
    dailyCompletion[d].total++;
    if (isDone) dailyCompletion[d].done++;

    if (!habitsByDay[d]) habitsByDay[d] = [];
    habitsByDay[d].push({name: habitName, done: isDone});

    totalHabitSlots++;
    if (isDone) totalHabitDone++;
  }
}

// Porcentajes por habito
for (const [name, s] of Object.entries(habitStats)) {
  s.pct = s.total > 0 ? Math.round((s.done / s.total) * 100) : 0;
}

// Top y bottom habitos
const habitList = Object.entries(habitStats)
  .map(([name, s]) => ({name, done: s.done, total: s.total, pct: s.pct}))
  .sort((a,b) => b.pct - a.pct);

const top5Habits = habitList.slice(0, 5);
const bottom5Habits = habitList.filter(h => h.total > 0).slice(-5).reverse();
const topHabit = habitList[0] || {name: 'N/A', pct: 0};
const bottomHabit = habitList.filter(h => h.total > 0).pop() || {name: 'N/A', pct: 100};

// Habitos perfectos (100%) y habitos en 0%
const perfectHabits = habitList.filter(h => h.pct === 100);
const zeroHabits = habitList.filter(h => h.pct === 0 && h.total > 0);
const criticalHabits = habitList.filter(h => h.pct > 0 && h.pct < 30 && h.total > 0);

// Mejor y peor dia
let bestDay = {day: 0, pct: 0, done: 0, total: 0};
let worstDay = {day: 0, pct: 100, done: 0, total: 0};
const dailyPctArray = [];

for (const [d, data] of Object.entries(dailyCompletion)) {
  const pct = data.total > 0 ? Math.round((data.done / data.total) * 100) : 0;
  dailyPctArray.push({day: parseInt(d), pct, done: data.done, total: data.total});
  if (pct > bestDay.pct) bestDay = {day: parseInt(d), pct, done: data.done, total: data.total};
  if (pct < worstDay.pct && data.total > 0) worstDay = {day: parseInt(d), pct, done: data.done, total: data.total};
}

// Dias perfectos (100%) y dias en 0%
const perfectDays = dailyPctArray.filter(d => d.pct === 100);
const zeroDays = dailyPctArray.filter(d => d.pct === 0);
const abovePct70 = dailyPctArray.filter(d => d.pct >= 70);
const belowPct50 = dailyPctArray.filter(d => d.pct < 50);

// Promedio diario
const avgDailyPct = dailyPctArray.length > 0
  ? Math.round(dailyPctArray.reduce((s,d) => s + d.pct, 0) / dailyPctArray.length)
  : 0;

// Tendencia (primera mitad vs segunda mitad)
const mid = Math.floor(dailyPctArray.length / 2);
const firstHalf = dailyPctArray.slice(0, mid);
const secondHalf = dailyPctArray.slice(mid);
const avgFirst = firstHalf.length > 0 ? Math.round(firstHalf.reduce((s,d) => s+d.pct,0)/firstHalf.length) : 0;
const avgSecond = secondHalf.length > 0 ? Math.round(secondHalf.reduce((s,d) => s+d.pct,0)/secondHalf.length) : 0;
const habitTrend = avgSecond > avgFirst ? 'mejorando' : avgSecond < avgFirst ? 'decayendo' : 'estable';
const habitTrendDiff = Math.abs(avgSecond - avgFirst);

const overallHabitPct = totalHabitSlots > 0 ? Math.round((totalHabitDone / totalHabitSlots) * 100) : 0;

// Racha
let currentConsecutive = 0;
const sortedDays = dailyPctArray.sort((a,b) => b.day - a.day);
for (const d of sortedDays) {
  if (d.pct >= 70) currentConsecutive++;
  else break;
}

// Racha maxima en el periodo
let maxStreak = 0, tempStreak = 0;
const sortedAsc = [...dailyPctArray].sort((a,b) => a.day - b.day);
for (const d of sortedAsc) {
  if (d.pct >= 70) { tempStreak++; if (tempStreak > maxStreak) maxStreak = tempStreak; }
  else tempStreak = 0;
}

// Total habitos trackeados
const totalHabitsTracked = habitList.length;

// ═══════════════════════════════════════════════════════════════
// OUTREACH — EXTRACCION PROFUNDA
// ═══════════════════════════════════════════════════════════════
const emailsThisPeriod = emailLogRaw.filter(e => {
  if (!e.email_sent_date) return false;
  const d = new Date(e.email_sent_date);
  return d >= periodStart && d <= periodEnd;
});

const totalSent = emailsThisPeriod.length;
const totalDelivered = emailsThisPeriod.filter(e => e.delivery_status === 'sent').length;
const totalFailed = emailsThisPeriod.filter(e => e.delivery_status === 'failed').length;
const totalReplied = emailsThisPeriod.filter(e => String(e.reply_detected).toLowerCase() === 'true').length;
const initialEmails = emailsThisPeriod.filter(e => (e.variant||'').startsWith('initial')).length;
const followupEmails = totalSent - initialEmails;
const deliveryRate = totalSent > 0 ? Math.round((totalDelivered/totalSent)*100) : 0;
const replyRate = totalDelivered > 0 ? Math.round((totalReplied/totalDelivered)*100) : 0;
const failRate = totalSent > 0 ? Math.round((totalFailed/totalSent)*100) : 0;

// Promedio correos por dia
const avgEmailsPerDay = daysElapsed > 0 ? Math.round((totalSent / daysElapsed) * 10) / 10 : 0;

// Correos por dia del periodo
const emailsByDate = {};
for (const e of emailsThisPeriod) {
  const dateKey = (e.email_sent_date || '').split('T')[0];
  if (!emailsByDate[dateKey]) emailsByDate[dateKey] = {sent: 0, delivered: 0, failed: 0, replied: 0};
  emailsByDate[dateKey].sent++;
  if (e.delivery_status === 'sent') emailsByDate[dateKey].delivered++;
  if (e.delivery_status === 'failed') emailsByDate[dateKey].failed++;
  if (String(e.reply_detected).toLowerCase() === 'true') emailsByDate[dateKey].replied++;
}

// Dia con mas envios
let peakSendDay = {date: 'N/A', count: 0};
for (const [date, data] of Object.entries(emailsByDate)) {
  if (data.sent > peakSendDay.count) peakSendDay = {date, count: data.sent, delivered: data.delivered};
}

// Dias activos vs inactivos
const activeSendDays = Object.keys(emailsByDate).length;
const inactiveSendDays = daysElapsed - activeSendDays;

// Mejor dia de la semana
const byDayOfWeek = {0:'Domingo',1:'Lunes',2:'Martes',3:'Miercoles',4:'Jueves',5:'Viernes',6:'Sabado'};
const sentByDay = {}, repliedByDay = {}, deliveredByDay = {};
for (const e of emailsThisPeriod) {
  if (!e.email_sent_date) continue;
  const d = new Date(e.email_sent_date).getDay();
  const dayName = byDayOfWeek[d];
  sentByDay[dayName] = (sentByDay[dayName] || 0) + 1;
  if (e.delivery_status === 'sent') deliveredByDay[dayName] = (deliveredByDay[dayName] || 0) + 1;
  if (String(e.reply_detected).toLowerCase() === 'true') repliedByDay[dayName] = (repliedByDay[dayName] || 0) + 1;
}

// Ranking de dias
const dayRanking = Object.entries(sentByDay)
  .map(([day, sent]) => ({
    day, sent, delivered: deliveredByDay[day] || 0,
    replied: repliedByDay[day] || 0,
    replyRate: sent > 0 ? Math.round(((repliedByDay[day]||0)/sent)*100) : 0
  }))
  .sort((a,b) => b.sent - a.sent);

let bestSendDay = dayRanking[0] || {day: 'N/A', rate: 0, sent: 0, replied: 0};

// Subjects mas usados
const subjectCount = {};
for (const e of emailsThisPeriod) {
  const subj = (e.subject || '').trim();
  if (subj) subjectCount[subj] = (subjectCount[subj] || 0) + 1;
}
const topSubjects = Object.entries(subjectCount)
  .sort((a,b) => b[1] - a[1])
  .slice(0, 5)
  .map(([subject, count]) => ({subject, count}));

// Por nicho
const nicheStats = {};
for (const lead of leadsRaw) {
  const niche = lead.niche || 'Sin nicho';
  if (!nicheStats[niche]) nicheStats[niche] = {total: 0, contacted: 0, replied: 0, withEmail: 0};
  nicheStats[niche].total++;
  if (lead.email && lead.email !== 'N/A' && lead.email.includes('@')) nicheStats[niche].withEmail++;
  if (String(lead.contactado).toUpperCase() === 'TRUE') nicheStats[niche].contacted++;
  if (String(lead.respondio).toUpperCase() === 'TRUE') nicheStats[niche].replied++;
}
const topNiches = Object.entries(nicheStats)
  .sort((a,b) => b[1].total - a[1].total)
  .slice(0, 8)
  .map(([n, s]) => ({
    niche: n, ...s,
    contactRate: s.withEmail > 0 ? Math.round((s.contacted/s.withEmail)*100) : 0,
    replyRate: s.contacted > 0 ? Math.round((s.replied/s.contacted)*100) : 0
  }));

// Por tier
const tierStats = {};
for (const lead of leadsRaw) {
  const tier = lead.tier || 'Sin tier';
  if (!tierStats[tier]) tierStats[tier] = {total: 0, contacted: 0, replied: 0, withEmail: 0};
  tierStats[tier].total++;
  if (lead.email && lead.email !== 'N/A') tierStats[tier].withEmail++;
  if (String(lead.contactado).toUpperCase() === 'TRUE') tierStats[tier].contacted++;
  if (String(lead.respondio).toUpperCase() === 'TRUE') tierStats[tier].replied++;
}
const tierBreakdown = Object.entries(tierStats)
  .sort(([a],[b]) => a.localeCompare(b))
  .map(([t, s]) => ({
    tier: t, ...s,
    contactRate: s.withEmail > 0 ? Math.round((s.contacted/s.withEmail)*100) : 0,
    replyRate: s.contacted > 0 ? Math.round((s.replied/s.contacted)*100) : 0
  }));

// Por ciudad
const cityStats = {};
for (const lead of leadsRaw) {
  const city = (lead.city || '').trim();
  if (!city || city === 'N/A' || city.length < 3) continue;
  if (!cityStats[city]) cityStats[city] = {total: 0, contacted: 0, replied: 0};
  cityStats[city].total++;
  if (String(lead.contactado).toUpperCase() === 'TRUE') cityStats[city].contacted++;
  if (String(lead.respondio).toUpperCase() === 'TRUE') cityStats[city].replied++;
}
const topCities = Object.entries(cityStats)
  .sort((a,b) => b[1].total - a[1].total)
  .slice(0, 5)
  .map(([c, s]) => ({city: c, ...s, replyRate: s.contacted > 0 ? Math.round((s.replied/s.contacted)*100) : 0}));

// A/B Test
const variantStats = {};
for (const e of emailsThisPeriod) {
  const v = (e.variant || '').includes('_A') ? 'A' : (e.variant || '').includes('_B') ? 'B' : 'other';
  if (!variantStats[v]) variantStats[v] = {sent: 0, delivered: 0, replied: 0};
  variantStats[v].sent++;
  if (e.delivery_status === 'sent') variantStats[v].delivered++;
  if (String(e.reply_detected).toLowerCase() === 'true') variantStats[v].replied++;
}
const abTest = Object.entries(variantStats).map(([v,s]) => ({
  variant: v, ...s,
  deliveryRate: s.sent > 0 ? Math.round((s.delivered/s.sent)*100) : 0,
  replyRate: s.delivered > 0 ? Math.round((s.replied/s.delivered)*100) : 0
})).sort((a,b) => b.replyRate - a.replyRate);

// Leads
const totalLeads = leadsRaw.length;
const leadsWithEmail = leadsRaw.filter(l => l.email && l.email !== 'N/A' && l.email.includes('@')).length;
const contactedLeads = leadsRaw.filter(l => String(l.contactado).toUpperCase() === 'TRUE').length;
const repliedLeads = leadsRaw.filter(l => String(l.respondio).toUpperCase() === 'TRUE').length;
const pendingLeads = leadsWithEmail - contactedLeads;
const leadContactRate = leadsWithEmail > 0 ? Math.round((contactedLeads/leadsWithEmail)*100) : 0;
const leadReplyRate = contactedLeads > 0 ? Math.round((repliedLeads/contactedLeads)*100) : 0;

// Outreach control stats
const awaitingResponse = controlRaw.filter(c => c.response_status === 'awaiting').length;
const convertedLeads = controlRaw.filter(c => c.response_status === 'converted').length;
const unsubscribed = controlRaw.filter(c => c.response_status === 'unsubscribed').length;

// Followups pendientes
const followupsPending = controlRaw.filter(c => {
  if (c.response_status !== 'awaiting') return false;
  if (!c.next_followup_date) return false;
  return new Date(c.next_followup_date) <= now;
}).length;

// Proyeccion
const daysInMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate();
const daysRemaining = daysInMonth - now.getDate();
const dailyRateEmails = daysElapsed > 0 ? totalSent / daysElapsed : 0;
const projectedMonthlyEmails = Math.round(dailyRateEmails * daysInMonth);
const projectedReplies = Math.round(projectedMonthlyEmails * (replyRate/100));
const burnRate = pendingLeads > 0 && dailyRateEmails > 0 ? Math.round(pendingLeads / dailyRateEmails) : 999;

// ═══ CORRELACION ═══
const dayCorrelation = [];
for (const d of daysToAnalyze) {
  const habData = dailyCompletion[d];
  const habPct = habData ? Math.round((habData.done/habData.total)*100) : 0;
  const month = targetMonth + 1;
  const dayStr = `${targetYear}-${String(month).padStart(2,'0')}-${String(d).padStart(2,'0')}`;
  const emailsDay = emailsThisPeriod.filter(e => (e.email_sent_date||'').startsWith(dayStr)).length;
  dayCorrelation.push({day: d, habitPct: habPct, emailsSent: emailsDay});
}
const highHabitDays = dayCorrelation.filter(d => d.habitPct >= 80);
const avgEmailsHighHabit = highHabitDays.length > 0 ? Math.round(highHabitDays.reduce((s,d) => s+d.emailsSent,0)/highHabitDays.length * 10) / 10 : 0;
const lowHabitDays = dayCorrelation.filter(d => d.habitPct < 60);
const avgEmailsLowHabit = lowHabitDays.length > 0 ? Math.round(lowHabitDays.reduce((s,d) => s+d.emailsSent,0)/lowHabitDays.length * 10) / 10 : 0;
const correlationDelta = avgEmailsHighHabit - avgEmailsLowHabit;
const correlationInsight = correlationDelta > 0
  ? `En dias con +80% habitos se enviaron ${avgEmailsHighHabit} correos/dia vs ${avgEmailsLowHabit} en dias con -60%. Diferencia: ${correlationDelta} correos/dia.`
  : `No hay correlacion significativa entre disciplina y volumen de outreach en este periodo.`;

// ═══ SCORE ═══
const habitScore = overallHabitPct;
const outreachScore = Math.min(100, Math.round((totalDelivered / Math.max(1, daysElapsed * 3)) * 100));
const replyScore = Math.min(100, replyRate * 3);
const overallScore = Math.round((habitScore * 0.35) + (outreachScore * 0.40) + (replyScore * 0.25));
const scoreLabel = overallScore >= 85 ? 'ELITE' : overallScore >= 70 ? 'SOLIDO' : overallScore >= 55 ? 'REGULAR' : 'CRITICO';

// ═══ RECOMENDACIONES (sin emojis) ═══
const recommendations = [];
if (overallHabitPct < 70) recommendations.push(`Habitos al ${overallHabitPct}%. Priorizar "${bottomHabit.name}" (${bottomHabit.pct}%).`);
if (zeroHabits.length > 0) recommendations.push(`${zeroHabits.length} habito(s) en 0%: ${zeroHabits.map(h=>h.name).join(', ')}. Eliminar o ejecutar.`);
if (habitTrend === 'decayendo') recommendations.push(`Tendencia negativa en habitos: ${avgFirst}% primera mitad vs ${avgSecond}% segunda mitad.`);
if (replyRate < 5 && totalSent > 10) recommendations.push(`Tasa de respuesta al ${replyRate}%. Revisar copy y subjects.`);
if (failRate > 10 && totalFailed > 3) recommendations.push(`${totalFailed} correos fallidos (${failRate}%). Limpiar lista de emails.`);
if (inactiveSendDays > daysElapsed * 0.4) recommendations.push(`${inactiveSendDays} de ${daysElapsed} dias sin enviar. Mantener cadencia diaria.`);
if (abTest.length >= 2 && abTest[0].replyRate !== abTest[1].replyRate) recommendations.push(`Variante ${abTest[0].variant} supera en conversion (${abTest[0].replyRate}% vs ${abTest[1]?.replyRate || 0}%).`);
if (burnRate < 30) recommendations.push(`Pipeline se agota en ~${burnRate} dias al ritmo actual. Generar leads nuevos.`);
if (pendingLeads < 50) recommendations.push(`Solo ${pendingLeads} leads pendientes. Pipeline critico.`);
if (followupsPending > 10) recommendations.push(`${followupsPending} follow-ups vencidos sin enviar.`);
if (currentConsecutive >= 5) recommendations.push(`Racha activa de ${currentConsecutive} dias. Mantener.`);
if (maxStreak > currentConsecutive && maxStreak >= 3) recommendations.push(`Racha maxima del periodo: ${maxStreak} dias. Actual: ${currentConsecutive}.`);

return [{ json: {
  config,
  periodoCompleto,
  habits: {
    overallPct: overallHabitPct,
