    burnRate, daysRemaining
  },
  correlation: {
    insight: correlationInsight,
    avgEmailsHighHabit, avgEmailsLowHabit,
    delta: correlationDelta,
    highHabitDaysCount: highHabitDays.length,
    lowHabitDaysCount: lowHabitDays.length
  },
  score: { overall: overallScore, label: scoreLabel, habit: habitScore, outreach: outreachScore, reply: replyScore },
